//! NAPI bindings exposing rayon-parallel inference kernels to Node.js.
//!
//! Zero-copy: Node `Buffer` arguments are reinterpreted as `&[f32]` / `&mut [f32]`
//! via `bytemuck::cast_slice`. No allocations on the hot path except a small
//! per-thread scratch vector (seq_len f32s for attention; hidden/intermediate
//! stripes for FFN).
//!
//! Three kernels are exported:
//!   - `forward_multihead_attention`       -- dense GQA attention (reference).
//!   - `forward_median_shift_attention`    -- Angle 4: median-shift truncation.
//!   - `forward_ffn_column_tp`             -- Angle 5: column-parallel SwiGLU FFN.

#![cfg(not(target_arch = "wasm32"))]

use gnosis_frf::prelude::*;
use napi::bindgen_prelude::{Buffer, Uint32Array};
use napi_derive::napi;

use crate::inference_bowl::{bowl_filtered_attention_prune, BowlPruneConfig};
use std::sync::OnceLock;

// Integration tests that exercise the `*_impl` free functions directly, without
// going through the NAPI Buffer wrappers.
#[cfg(test)]
mod inference_ffi_tests;

/// Gate for the bowl Q-filter alternative to the median-shift binary prune.
///
/// Off by default: when `GNOSIS_CHAOS_BOWL_FILTER=1` is set in the
/// process environment at first call, the median-shift kernel routes the
/// per-head prune through `inference_bowl::bowl_filtered_attention_prune`
/// (damps below-cutoff positions by `damping+1` instead of zeroing them
/// and renormalizing only over the kept set). Read once and cached so the
/// rayon-parallel hot loop does not re-parse the env var per head.
///
/// The 2026-05-03 bowl-mesh falsification showed that at K=1 the legacy
/// binary mask corrupts the cross-layer residual sum; the bowl path is the
/// proposed mitigation. Both code paths must remain runnable until the
/// bowl path is validated against a reference oracle.
fn bowl_filter_enabled() -> bool {
    // Test-only override so unit tests can flip the gate without depending
    // on process-level env var ordering. Atomic so it is safe inside the
    // rayon-parallel head closure.
    #[cfg(test)]
    {
        use std::sync::atomic::Ordering;
        let override_val = BOWL_FILTER_TEST_OVERRIDE.load(Ordering::Relaxed);
        // 0 = unset (fall through to env-var cache), 1 = forced off, 2 = forced on.
        if override_val == 1 {
            return false;
        } else if override_val == 2 {
            return true;
        }
    }
    static FLAG: OnceLock<bool> = OnceLock::new();
    *FLAG.get_or_init(|| {
        // Default ON. Set GNOSIS_CHAOS_BOWL_FILTER=0 to disable.
        !std::env::var("GNOSIS_CHAOS_BOWL_FILTER")
            .is_ok_and(|v| v == "0" || v.eq_ignore_ascii_case("false"))
    })
}

/// Test-only override for `bowl_filter_enabled()`. 0 = consult env var
/// cache (production behavior); 1 = force OFF; 2 = force ON. Lets the
/// unit test exercise both branches inside one process without flaky
/// env-var ordering against the `OnceLock` cache.
#[cfg(test)]
static BOWL_FILTER_TEST_OVERRIDE: std::sync::atomic::AtomicU8 = std::sync::atomic::AtomicU8::new(0);

// ---------------------------------------------------------------------------
// Kernel 1: dense multi-head attention (pre-existing)
// ---------------------------------------------------------------------------

/// Multi-head attention forward pass, single decode-time query per head.
///
/// Shapes (contiguous row-major f32):
///   q:   [num_heads    * head_dim]
///   k:   [num_kv_heads * seq_len * head_dim]
///   v:   [num_kv_heads * seq_len * head_dim]
///   out: [num_heads    * head_dim]          -- overwritten
///
/// GQA mapping: `kv_head = h / (num_heads / num_kv_heads)`. Requires
/// `num_heads % num_kv_heads == 0`.
#[napi]
#[allow(clippy::too_many_arguments)]
pub fn forward_multihead_attention(
    q: Buffer,
    k: Buffer,
    v: Buffer,
    mut out: Buffer,
    seq_len: u32,
    head_dim: u32,
    num_heads: u32,
    num_kv_heads: u32,
    scale: f64,
) -> napi::Result<()> {
    let q_slice: &[f32] = bytemuck::cast_slice(q.as_ref());
    let k_slice: &[f32] = bytemuck::cast_slice(k.as_ref());
    let v_slice: &[f32] = bytemuck::cast_slice(v.as_ref());
    let out_slice: &mut [f32] = bytemuck::cast_slice_mut(out.as_mut());

    forward_multihead_attention_impl(
        q_slice,
        k_slice,
        v_slice,
        out_slice,
        seq_len as usize,
        head_dim as usize,
        num_heads as usize,
        num_kv_heads as usize,
        scale as f32,
    )
    .map_err(napi::Error::from_reason)
}

pub(crate) fn forward_multihead_attention_impl(
    q_slice: &[f32],
    k_slice: &[f32],
    v_slice: &[f32],
    out_slice: &mut [f32],
    seq_len: usize,
    head_dim: usize,
    num_heads: usize,
    num_kv_heads: usize,
    scale: f32,
) -> Result<(), String> {
    if num_heads == 0 || num_kv_heads == 0 || head_dim == 0 || seq_len == 0 {
        return Err("forward_multihead_attention: zero-sized dimension".into());
    }
    if num_heads % num_kv_heads != 0 {
        return Err(format!(
            "num_heads ({}) must be divisible by num_kv_heads ({})",
            num_heads, num_kv_heads
        ));
    }
    let heads_per_kv = num_heads / num_kv_heads;

    let expected_q = num_heads * head_dim;
    let expected_kv = num_kv_heads * seq_len * head_dim;
    let expected_out = num_heads * head_dim;
    if q_slice.len() != expected_q
        || k_slice.len() != expected_kv
        || v_slice.len() != expected_kv
        || out_slice.len() != expected_out
    {
        return Err(format!(
            "shape mismatch: q={} (expect {}), k={} (expect {}), v={} (expect {}), out={} (expect {})",
            q_slice.len(), expected_q,
            k_slice.len(), expected_kv,
            v_slice.len(), expected_kv,
            out_slice.len(), expected_out,
        ));
    }

    out_slice
        .par_chunks_mut(head_dim)
        .enumerate()
        .for_each(|(h, out_head)| {
            let kv_head = h / heads_per_kv;
            let q_off = h * head_dim;
            let kv_base = kv_head * seq_len * head_dim;

            let q_head = &q_slice[q_off..q_off + head_dim];
            let k_head = &k_slice[kv_base..kv_base + seq_len * head_dim];
            let v_head = &v_slice[kv_base..kv_base + seq_len * head_dim];

            let mut scores = vec![0.0f32; seq_len];
            let mut max_score = f32::NEG_INFINITY;
            for t in 0..seq_len {
                let k_row = &k_head[t * head_dim..(t + 1) * head_dim];
                let mut dot = 0.0f32;
                for d in 0..head_dim {
                    dot += q_head[d] * k_row[d];
                }
                let s = dot * scale;
                scores[t] = s;
                if s > max_score {
                    max_score = s;
                }
            }

            let mut z = 0.0f32;
            for s in scores.iter_mut() {
                *s = (*s - max_score).exp();
                z += *s;
            }
            let inv_z = if z > 0.0 { 1.0 / z } else { 0.0 };

            for d in 0..head_dim {
                out_head[d] = 0.0;
            }
            for t in 0..seq_len {
                let w = scores[t] * inv_z;
                let v_row = &v_head[t * head_dim..(t + 1) * head_dim];
                for d in 0..head_dim {
                    out_head[d] += w * v_row[d];
                }
            }
        });

    Ok(())
}

// ---------------------------------------------------------------------------
// Kernel 2: median-shift attention (Angle 4)
// ---------------------------------------------------------------------------

/// Aggregated telemetry across all heads for one `forward_median_shift_attention`
/// call. Mirrors `AttentionTelemetry` from median-shift-attention.ts, summed
/// over heads; booleans become counts.
#[napi(object)]
pub struct MedianShiftTelemetry {
    /// Sum of seq_len over heads (num_heads * seq_len for a uniform batch).
    pub seq_len: u32,
    /// Total positions kept across heads.
    pub kept_count: u32,
    /// Total positions dropped across heads.
    pub dropped_count: u32,
    /// Sum of Z_full over heads. f64 to avoid loss across many heads.
    pub z_full: f64,
    /// Sum of Z_dropped over heads.
    pub z_dropped: f64,
    /// z_dropped / z_full, averaged over heads (simple arithmetic mean).
    pub dropped_mass_fraction: f64,
    /// True iff any head fell back to full softmax on this call.
    pub fell_back_to_full_softmax: bool,
    /// Count of heads that fell back (0..=num_heads).
    pub fallback_head_count: u32,
}

/// Median-shift attention forward pass. Drops positions at or below the
/// row median (shifted softmax is invariant), renormalises over the kept set
/// only, and falls back to full softmax per-head when the dropped mass fraction
/// exceeds `dropped_mass_ceiling`.
///
/// See `apps/edge-workers/src/lib/distributed-inference/median-shift-attention.ts`.
#[napi]
#[allow(clippy::too_many_arguments)]
pub fn forward_median_shift_attention(
    q: Buffer,
    k: Buffer,
    v: Buffer,
    mut out: Buffer,
    seq_len: u32,
    head_dim: u32,
    num_heads: u32,
    num_kv_heads: u32,
    scale: f64,
    dropped_mass_ceiling: f64,
) -> napi::Result<MedianShiftTelemetry> {
    let q_slice: &[f32] = bytemuck::cast_slice(q.as_ref());
    let k_slice: &[f32] = bytemuck::cast_slice(k.as_ref());
    let v_slice: &[f32] = bytemuck::cast_slice(v.as_ref());
    let out_slice: &mut [f32] = bytemuck::cast_slice_mut(out.as_mut());

    forward_median_shift_attention_impl(
        q_slice,
        k_slice,
        v_slice,
        out_slice,
        seq_len as usize,
        head_dim as usize,
        num_heads as usize,
        num_kv_heads as usize,
        scale as f32,
        dropped_mass_ceiling as f32,
    )
    .map_err(napi::Error::from_reason)
}

/// Per-head telemetry, later folded into `MedianShiftTelemetry`.
#[derive(Clone, Copy, Debug)]
pub(crate) struct HeadTelemetry {
    pub seq_len: usize,
    pub kept_count: usize,
    pub dropped_count: usize,
    pub z_full: f32,
    pub z_dropped: f32,
    pub dropped_mass_fraction: f32,
    pub fell_back: bool,
}

#[allow(clippy::too_many_arguments)]
pub(crate) fn forward_median_shift_attention_impl(
    q_slice: &[f32],
    k_slice: &[f32],
    v_slice: &[f32],
    out_slice: &mut [f32],
    seq_len: usize,
    head_dim: usize,
    num_heads: usize,
    num_kv_heads: usize,
    scale: f32,
    dropped_mass_ceiling: f32,
) -> Result<MedianShiftTelemetry, String> {
    if num_heads == 0 || num_kv_heads == 0 || head_dim == 0 || seq_len == 0 {
        return Err("forward_median_shift_attention: zero-sized dimension".into());
    }
    if num_heads % num_kv_heads != 0 {
        return Err(format!(
            "num_heads ({}) must be divisible by num_kv_heads ({})",
            num_heads, num_kv_heads
        ));
    }
    let heads_per_kv = num_heads / num_kv_heads;

    let expected_q = num_heads * head_dim;
    let expected_kv = num_kv_heads * seq_len * head_dim;
    let expected_out = num_heads * head_dim;
    if q_slice.len() != expected_q
        || k_slice.len() != expected_kv
        || v_slice.len() != expected_kv
        || out_slice.len() != expected_out
    {
        return Err(format!(
            "shape mismatch: q={} (expect {}), k={} (expect {}), v={} (expect {}), out={} (expect {})",
            q_slice.len(), expected_q,
            k_slice.len(), expected_kv,
            v_slice.len(), expected_kv,
            out_slice.len(), expected_out,
        ));
    }

    // Per-head work; `for_each_init` gives each worker a reusable scratch pair
    // (scores, sort_scratch for quickselect). One telemetry slot per head so we
    // can fold sequentially afterwards.
    let mut per_head_tel: Vec<HeadTelemetry> = vec![
        HeadTelemetry {
            seq_len,
            kept_count: 0,
            dropped_count: 0,
            z_full: 0.0,
            z_dropped: 0.0,
            dropped_mass_fraction: 0.0,
            fell_back: false,
        };
        num_heads
    ];

    // We need to mutably borrow disjoint chunks of `out_slice` AND write the
    // per-head telemetry. Zip the output stripes with the telemetry slots.
    out_slice
        .par_chunks_mut(head_dim)
        .zip(per_head_tel.par_iter_mut())
        .enumerate()
        .for_each_init(
            || {
                (
                    vec![0.0f32; seq_len],
                    vec![0.0f32; seq_len],
                    vec![0.0f32; seq_len],
                )
            },
            |(scores, exps_full, sort_scratch), (h, (out_head, tel))| {
                let kv_head = h / heads_per_kv;
                let q_off = h * head_dim;
                let kv_base = kv_head * seq_len * head_dim;

                let q_head = &q_slice[q_off..q_off + head_dim];
                let k_head = &k_slice[kv_base..kv_base + seq_len * head_dim];
                let v_head = &v_slice[kv_base..kv_base + seq_len * head_dim];

                // 1. Q.K^T * scale
                let mut max_score = f32::NEG_INFINITY;
                for t in 0..seq_len {
                    let k_row = &k_head[t * head_dim..(t + 1) * head_dim];
                    let mut dot = 0.0f32;
                    for d in 0..head_dim {
                        dot += q_head[d] * k_row[d];
                    }
                    let s = dot * scale;
                    scores[t] = s;
                    if s > max_score {
                        max_score = s;
                    }
                }

                // 2. Full-softmax exponentials (max-subtracted) and Z_full.
                //    Needed for both fallback output and telemetry.
                let mut z_full = 0.0f32;
                for t in 0..seq_len {
                    let e = (scores[t] - max_score).exp();
                    exps_full[t] = e;
                    z_full += e;
                }

                // Zero the output stripe for accumulation.
                for d in 0..head_dim {
                    out_head[d] = 0.0;
                }

                // Degenerate Z_full: emit uniform mixture of values.
                if !z_full.is_finite() || z_full <= 0.0 {
                    let u = 1.0f32 / seq_len as f32;
                    for t in 0..seq_len {
                        let v_row = &v_head[t * head_dim..(t + 1) * head_dim];
                        for d in 0..head_dim {
                            out_head[d] += u * v_row[d];
                        }
                    }
                    *tel = HeadTelemetry {
                        seq_len,
                        kept_count: seq_len,
                        dropped_count: 0,
                        z_full: 0.0,
                        z_dropped: 0.0,
                        dropped_mass_fraction: 0.0,
                        fell_back: true,
                    };
                    return;
                }

                // Bowl Q-filter branch (gated). When enabled, route the
                // per-head prune through `bowl_filtered_attention_prune`:
                // below-cutoff positions are damped by (damping+1) instead
                // of zeroed, and the softmax is renormalized by
                // `z_kept + z_damped` rather than `z_kept` alone. This
                // preserves the cross-layer residual sum that the binary
                // mask was destroying at K=1 in the 2026-05-03 bowl-mesh
                // falsification. The legacy median-shift path below is
                // unchanged and remains the default until the bowl path is
                // validated against the oracle.
                if bowl_filter_enabled() {
                    // Compute the median cutoff on a scratch copy — same
                    // policy as the legacy path, but inlined here so the
                    // bowl branch is self-contained.
                    sort_scratch.clear();
                    sort_scratch.extend_from_slice(&scores[..seq_len]);
                    let cutoff = {
                        let mid = seq_len / 2;
                        let (_, m, _) = sort_scratch.select_nth_unstable_by(mid, |a, b| {
                            a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal)
                        });
                        let m_val = *m;
                        if seq_len & 1 == 1 {
                            m_val
                        } else {
                            let mut lower_max = f32::NEG_INFINITY;
                            for v in &sort_scratch[..mid] {
                                if *v > lower_max {
                                    lower_max = *v;
                                }
                            }
                            0.5 * (m_val + lower_max)
                        }
                    };

                    // Materialize per-position value rows for the bowl
                    // primitive. The primitive owns its allocation; this
                    // is the cost of the gated path. `values` is shaped
                    // [seq_len][head_dim], matching the flat `v_head`
                    // stride.
                    let values_rows: Vec<Vec<f32>> = (0..seq_len)
                        .map(|t| v_head[t * head_dim..(t + 1) * head_dim].to_vec())
                        .collect();

                    let result = bowl_filtered_attention_prune(
                        &scores[..seq_len],
                        &values_rows,
                        cutoff,
                        BowlPruneConfig::default(),
                    );

                    // Adapt the bowl result back into the caller-visible
                    // stripe + telemetry. `out_head` was zeroed at step 2;
                    // copy the bowl out_head into it (length matches by
                    // construction). If the bowl emitted an empty
                    // out_head (caller-bug edge case), leave the zeroed
                    // stripe and mark fallback so callers see the anomaly.
                    if result.out_head.len() == head_dim {
                        for d in 0..head_dim {
                            out_head[d] = result.out_head[d];
                        }
                        // Bowl z accounting: legacy `z_full` here is
                        // mapped to `z_kept + z_damped` (the total
                        // partition the output was renormalized by);
                        // `z_dropped` is mapped to `z_damped` (the
                        // attenuated tail). The two regimes are not
                        // bitwise comparable to the legacy median-shift
                        // telemetry — they share field names but
                        // semantics differ. dropped_mass_fraction is
                        // `z_damped / z_total` rather than
                        // `z_dropped / z_full`.
                        let z_total = result.z_total();
                        let frac = if z_total > 0.0 {
                            result.z_damped / z_total
                        } else {
                            0.0
                        };
                        *tel = HeadTelemetry {
                            seq_len,
                            kept_count: result.kept_positions,
                            dropped_count: result.damped_positions,
                            z_full: z_total,
                            z_dropped: result.z_damped,
                            dropped_mass_fraction: frac,
                            fell_back: false,
                        };
                    } else {
                        // Empty out_head from the bowl primitive means a
                        // caller-side shape mismatch the primitive
                        // refused to silently handle. Mark this head as
                        // a fallback so the aggregate telemetry surfaces
                        // the anomaly; out_head remains zeroed.
                        *tel = HeadTelemetry {
                            seq_len,
                            kept_count: 0,
                            dropped_count: seq_len,
                            z_full: 0.0,
                            z_dropped: 0.0,
                            dropped_mass_fraction: 0.0,
                            fell_back: true,
                        };
                    }
                    return;
                }

                // Legacy median-shift path (default; UNCHANGED).
                // 3. Row median via partial quickselect on a scratch copy.
                sort_scratch.clear();
                sort_scratch.extend_from_slice(&scores[..seq_len]);
                let median = {
                    let mid = seq_len / 2;
                    let (_, m, _) = sort_scratch.select_nth_unstable_by(mid, |a, b| {
                        a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal)
                    });
                    let m_val = *m;
                    if seq_len & 1 == 1 {
                        m_val
                    } else {
                        // Lower half max is in sort_scratch[..mid]; compute it.
                        let mut lower_max = f32::NEG_INFINITY;
                        for v in &sort_scratch[..mid] {
                            if *v > lower_max {
                                lower_max = *v;
                            }
                        }
                        0.5 * (m_val + lower_max)
                    }
                };
                let cutoff = median;

                // 4. First pass: count kept + compute Z_dropped (from exps_full).
                //    Keep positions where `scores > cutoff` (strictly).
                let mut kept_count = 0usize;
                let mut z_dropped = 0.0f32;
                for t in 0..seq_len {
                    if scores[t] > cutoff {
                        kept_count += 1;
                    } else {
                        z_dropped += exps_full[t];
                    }
                }
                let dropped_mass_fraction = z_dropped / z_full;

                // 5. Fidelity guardrail -> fall back to full softmax for this head.
                if dropped_mass_fraction > dropped_mass_ceiling || kept_count == 0 {
                    let inv = 1.0f32 / z_full;
                    for t in 0..seq_len {
                        let w = exps_full[t] * inv;
                        if w < 1e-12 {
                            continue;
                        }
                        let v_row = &v_head[t * head_dim..(t + 1) * head_dim];
                        for d in 0..head_dim {
                            out_head[d] += w * v_row[d];
                        }
                    }
                    *tel = HeadTelemetry {
                        seq_len,
                        kept_count,
                        dropped_count: seq_len - kept_count,
                        z_full,
                        z_dropped,
                        dropped_mass_fraction,
                        fell_back: true,
                    };
                    return;
                }

                // 6. Softmax over kept set only. Z_kept = Z_full - Z_dropped
                //    (exact; this is the `keptMassExact` Lean lemma).
                let z_kept = z_full - z_dropped;
                let inv_z_kept = 1.0f32 / z_kept;
                for t in 0..seq_len {
                    if scores[t] <= cutoff {
                        continue;
                    }
                    let w = exps_full[t] * inv_z_kept;
                    if w < 1e-12 {
                        continue;
                    }
                    let v_row = &v_head[t * head_dim..(t + 1) * head_dim];
                    for d in 0..head_dim {
                        out_head[d] += w * v_row[d];
                    }
                }

                *tel = HeadTelemetry {
                    seq_len,
                    kept_count,
                    dropped_count: seq_len - kept_count,
                    z_full,
                    z_dropped,
                    dropped_mass_fraction,
                    fell_back: false,
                };
            },
        );

    // Fold per-head telemetry into the aggregate NAPI object.
    let mut agg_seq_len: u64 = 0;
    let mut agg_kept: u64 = 0;
    let mut agg_dropped: u64 = 0;
    let mut agg_z_full: f64 = 0.0;
    let mut agg_z_dropped: f64 = 0.0;
    let mut agg_fraction_sum: f64 = 0.0;
    let mut fallback_count: u32 = 0;
    for t in &per_head_tel {
        agg_seq_len += t.seq_len as u64;
        agg_kept += t.kept_count as u64;
        agg_dropped += t.dropped_count as u64;
        agg_z_full += t.z_full as f64;
        agg_z_dropped += t.z_dropped as f64;
        agg_fraction_sum += t.dropped_mass_fraction as f64;
        if t.fell_back {
            fallback_count += 1;
        }
    }
    let mean_fraction = if num_heads > 0 {
        agg_fraction_sum / num_heads as f64
    } else {
        0.0
    };

    Ok(MedianShiftTelemetry {
        seq_len: agg_seq_len as u32,
        kept_count: agg_kept as u32,
        dropped_count: agg_dropped as u32,
        z_full: agg_z_full,
        z_dropped: agg_z_dropped,
        dropped_mass_fraction: mean_fraction,
        fell_back_to_full_softmax: fallback_count > 0,
        fallback_head_count: fallback_count,
    })
}

// ---------------------------------------------------------------------------
// Kernel 3: column-parallel SwiGLU FFN (Angle 5)
// ---------------------------------------------------------------------------

/// Column-parallel SwiGLU feed-forward pass.
///
/// Shapes (row-major f32):
///   x:      [seq_len, hidden_dim]
///   w_up:   [hidden_dim, intermediate_dim]
///   w_gate: [hidden_dim, intermediate_dim]
///   w_down: [intermediate_dim, hidden_dim]
///   out:    [seq_len, hidden_dim]
///
/// Algorithm:
///   up   = x  @ w_up
///   gate = x  @ w_gate
///   act  = silu(gate) * up           (element-wise, SwiGLU)
///   out  = act @ w_down
///
/// TP split: the `intermediate_dim` is sharded across `num_shards` workers.
/// Each worker owns a contiguous column stripe of w_up / w_gate (and the same
/// row stripe of w_down), computes its partial act chunk, and produces a
/// partial contribution to `out`. We then sum-reduce partial outputs over
/// shards -- the "mesh fold" step. Bit-exactness guaranteed only up to float
/// summation order; Lean proof is on the real-arithmetic level.
#[napi]
#[allow(clippy::too_many_arguments)]
pub fn forward_ffn_column_tp(
    x: Buffer,
    w_up: Buffer,
    w_gate: Buffer,
    w_down: Buffer,
    mut out: Buffer,
    seq_len: u32,
    hidden_dim: u32,
    intermediate_dim: u32,
    num_shards: u32,
) -> napi::Result<()> {
    let x_slice: &[f32] = bytemuck::cast_slice(x.as_ref());
    let w_up_slice: &[f32] = bytemuck::cast_slice(w_up.as_ref());
    let w_gate_slice: &[f32] = bytemuck::cast_slice(w_gate.as_ref());
    let w_down_slice: &[f32] = bytemuck::cast_slice(w_down.as_ref());
    let out_slice: &mut [f32] = bytemuck::cast_slice_mut(out.as_mut());

    forward_ffn_column_tp_impl(
        x_slice,
        w_up_slice,
        w_gate_slice,
        w_down_slice,
        out_slice,
        seq_len as usize,
        hidden_dim as usize,
        intermediate_dim as usize,
        num_shards as usize,
    )
    .map_err(napi::Error::from_reason)
}

#[allow(clippy::too_many_arguments)]
pub(crate) fn forward_ffn_column_tp_impl(
    x: &[f32],
    w_up: &[f32],
    w_gate: &[f32],
    w_down: &[f32],
    out: &mut [f32],
    seq_len: usize,
    hidden_dim: usize,
    intermediate_dim: usize,
    num_shards: usize,
) -> Result<(), String> {
    if seq_len == 0 || hidden_dim == 0 || intermediate_dim == 0 || num_shards == 0 {
        return Err("forward_ffn_column_tp: zero-sized dimension".into());
    }
    if intermediate_dim % num_shards != 0 {
        return Err(format!(
            "intermediate_dim ({}) must be divisible by num_shards ({})",
            intermediate_dim, num_shards
        ));
    }
    let stripe = intermediate_dim / num_shards;

    let expected_x = seq_len * hidden_dim;
    let expected_w_up = hidden_dim * intermediate_dim;
    let expected_w_down = intermediate_dim * hidden_dim;
    let expected_out = seq_len * hidden_dim;
    if x.len() != expected_x
        || w_up.len() != expected_w_up
        || w_gate.len() != expected_w_up
        || w_down.len() != expected_w_down
        || out.len() != expected_out
    {
        return Err(format!(
            "shape mismatch: x={} (expect {}), w_up={} (expect {}), w_gate={} (expect {}), w_down={} (expect {}), out={} (expect {})",
            x.len(), expected_x,
            w_up.len(), expected_w_up,
            w_gate.len(), expected_w_up,
            w_down.len(), expected_w_down,
            out.len(), expected_out,
        ));
    }

    // Per-shard partial output, shaped [seq_len, hidden_dim]. rayon reduce
    // over an identity zero vector is the single-process analogue of an
    // MPI allreduce(sum) across TP ranks.
    let partials: Vec<f32> = (0..num_shards)
        .into_par_iter()
        .map(|shard| {
            let col_start = shard * stripe; // column offset into intermediate dim
                                            // Local act stripe: [seq_len, stripe]
            let mut act = vec![0.0f32; seq_len * stripe];

            for s in 0..seq_len {
                let x_row = &x[s * hidden_dim..(s + 1) * hidden_dim];
                let act_row = &mut act[s * stripe..(s + 1) * stripe];
                for c in 0..stripe {
                    let col = col_start + c;
                    // up[s,col]   = sum_h x[s,h] * w_up[h, col]
                    // gate[s,col] = sum_h x[s,h] * w_gate[h, col]
                    let mut up = 0.0f32;
                    let mut gate = 0.0f32;
                    for h in 0..hidden_dim {
                        let xv = x_row[h];
                        up += xv * w_up[h * intermediate_dim + col];
                        gate += xv * w_gate[h * intermediate_dim + col];
                    }
                    // SiLU(gate) * up
                    let sig = 1.0f32 / (1.0 + (-gate).exp());
                    act_row[c] = gate * sig * up;
                }
            }

            // Partial down-projection: out_part[s,h_out] = sum_{c in stripe}
            //                                act[s,c] * w_down[col_start+c, h_out]
            let mut out_part = vec![0.0f32; seq_len * hidden_dim];
            for s in 0..seq_len {
                let act_row = &act[s * stripe..(s + 1) * stripe];
                let out_row = &mut out_part[s * hidden_dim..(s + 1) * hidden_dim];
                for c in 0..stripe {
                    let col = col_start + c;
                    let w_row = &w_down[col * hidden_dim..(col + 1) * hidden_dim];
                    let av = act_row[c];
                    for h_out in 0..hidden_dim {
                        out_row[h_out] += av * w_row[h_out];
                    }
                }
            }
            out_part
        })
        .reduce(
            || vec![0.0f32; seq_len * hidden_dim],
            |mut a, b| {
                for (av, bv) in a.iter_mut().zip(b.iter()) {
                    *av += *bv;
                }
                a
            },
        );

    out.copy_from_slice(&partials);
    Ok(())
}

// ---------------------------------------------------------------------------
// Kernel 4: allreduce-sum fold (prismatic refraction, tensor-parallel settle)
// ---------------------------------------------------------------------------

/// Allreduce-sum fold across lane shards. Wraps
/// `bitwise::prismatic_refraction::settle_by_lane_with_float_sum`.
///
/// JS contract:
/// - `shards_concat`: Node `Buffer` containing the concatenation of every
///   shard's f32 payload, in arrival order. Each shard occupies
///   `floats_per_shard * 4` contiguous bytes.
/// - `lane_indices`: `Uint32Array` with one entry per shard giving that
///   shard's lane id. `lane_indices.len() == shards_concat.len() /
///   (floats_per_shard * 4)`.
/// - `lane_count`: number of output lanes.
/// - `floats_per_shard`: f32 count per shard (equivalently per lane output).
///
/// Returns a Node `Buffer` containing the concatenation of `lane_count`
/// per-lane sum vectors, each `floats_per_shard * 4` bytes. Lanes that
/// received no shards are emitted as all-zero vectors.
#[napi]
pub fn allreduce_float_sum(
    shards_concat: Buffer,
    lane_indices: Uint32Array,
    lane_count: u32,
    floats_per_shard: u32,
) -> napi::Result<Buffer> {
    let lane_count = lane_count as usize;
    let floats_per_shard = floats_per_shard as usize;
    let bytes_per_shard = floats_per_shard
        .checked_mul(4)
        .ok_or_else(|| napi::Error::from_reason("floats_per_shard * 4 overflows usize"))?;

    let concat: &[u8] = shards_concat.as_ref();
    let lanes: &[u32] = &lane_indices;
    let num_shards = lanes.len();

    let expected_concat = num_shards
        .checked_mul(bytes_per_shard)
        .ok_or_else(|| napi::Error::from_reason("num_shards * bytes_per_shard overflows"))?;
    if concat.len() != expected_concat {
        return Err(napi::Error::from_reason(format!(
            "shards_concat byte length {} != num_shards {} * floats_per_shard {} * 4",
            concat.len(),
            num_shards,
            floats_per_shard,
        )));
    }

    // Build the (lane, &[u8]) view expected by the bitwise API. Zero copy;
    // slices point into the caller's Buffer.
    let mut view: Vec<(u16, &[u8])> = Vec::with_capacity(num_shards);
    for (i, lane) in lanes.iter().enumerate() {
        if *lane > u16::MAX as u32 {
            return Err(napi::Error::from_reason(
                "lane index exceeds u16::MAX (bitwise API is u16-indexed)",
            ));
        }
        let start = i * bytes_per_shard;
        view.push((*lane as u16, &concat[start..start + bytes_per_shard]));
    }

    let settled = bitwise::prismatic_refraction::settle_by_lane_with_float_sum(
        &view,
        lane_count,
        floats_per_shard,
    )
    .map_err(napi::Error::from_reason)?;

    // Concatenate per-lane f32 outputs into a single Buffer. We could
    // reuse a scratch allocation per call, but lane_count * floats_per_shard
    // * 4 bytes is tiny next to attention/FFN buffers.
    let mut out_bytes: Vec<u8> = Vec::with_capacity(lane_count * bytes_per_shard);
    for lane in &settled {
        let lane_bytes: &[u8] = bytemuck::cast_slice(lane.as_slice());
        out_bytes.extend_from_slice(lane_bytes);
    }
    Ok(Buffer::from(out_bytes))
}

/// Dense matrix-vector multiply: `out = M * v` where `M` is `rows x cols`
/// in row-major layout and `v` has length `cols`. `out` must have length
/// `rows`. Single-threaded dot-product loop.
///
/// Primary hot-path replacement for `SIMDFallback.matVec`. The gemma4
/// forward pass calls this 7× per layer (Q/K/V/O + FFN up/gate/down) =
/// 420 calls per token on the 60-layer 31B model. Even single-threaded,
/// native AVX via rustc auto-vectorization expects 2-4× over WASM SIMD.
///
/// Safety envelope (fixes the 2026-04-20 v148 crash):
///   - `try_cast_slice` returns Err instead of panicking on alignment /
///     length mismatch, so a bad buffer becomes a NAPI error, not a
///     process abort.
///   - Explicit bounds checks on rows / cols / matrix / vector / output
///     sizes return NAPI error instead of runtime panic.
///   - The whole body runs under `catch_unwind`, so any stray panic
///     (including from rayon if we re-enable it later) is rethrown as
///     a NAPI error rather than crashing the Node process.
#[napi]
pub fn forward_matvec_f32(
    matrix: Buffer,
    vector: Buffer,
    mut out: Buffer,
    rows: u32,
    cols: u32,
    softcap: Option<f64>,
) -> napi::Result<()> {
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        forward_matvec_f32_inner(&matrix, &vector, &mut out, rows, cols, softcap)
    }));
    match result {
        Ok(inner) => inner,
        Err(panic) => {
            let msg = if let Some(s) = panic.downcast_ref::<&str>() {
                (*s).to_string()
            } else if let Some(s) = panic.downcast_ref::<String>() {
                s.clone()
            } else {
                "forward_matvec_f32: unknown panic".to_string()
            };
            Err(napi::Error::from_reason(format!(
                "forward_matvec_f32: caught panic: {}",
                msg
            )))
        }
    }
}

fn forward_matvec_f32_inner(
    matrix: &Buffer,
    vector: &Buffer,
    out: &mut Buffer,
    rows: u32,
    cols: u32,
    softcap: Option<f64>,
) -> napi::Result<()> {
    let m: &[f32] = match bytemuck::try_cast_slice::<u8, f32>(matrix.as_ref()) {
        Ok(s) => s,
        Err(e) => {
            return Err(napi::Error::from_reason(format!(
                "forward_matvec_f32: matrix cast failed: {}",
                e
            )));
        }
    };
    let v: &[f32] = match bytemuck::try_cast_slice::<u8, f32>(vector.as_ref()) {
        Ok(s) => s,
        Err(e) => {
            return Err(napi::Error::from_reason(format!(
                "forward_matvec_f32: vector cast failed: {}",
                e
            )));
        }
    };
    let o: &mut [f32] = match bytemuck::try_cast_slice_mut::<u8, f32>(out.as_mut()) {
        Ok(s) => s,
        Err(e) => {
            return Err(napi::Error::from_reason(format!(
                "forward_matvec_f32: out cast failed: {}",
                e
            )));
        }
    };
    let r = rows as usize;
    let c = cols as usize;
    if r == 0 || c == 0 {
        return Err(napi::Error::from_reason(
            "forward_matvec_f32: zero-sized dimension".to_string(),
        ));
    }
    let expected_m = match r.checked_mul(c) {
        Some(v) => v,
        None => {
            return Err(napi::Error::from_reason(
                "forward_matvec_f32: rows*cols overflows usize".to_string(),
            ));
        }
    };
    if m.len() != expected_m {
        return Err(napi::Error::from_reason(format!(
            "forward_matvec_f32: matrix len {} != rows*cols {}",
            m.len(),
            expected_m
        )));
    }
    if v.len() != c {
        return Err(napi::Error::from_reason(format!(
            "forward_matvec_f32: vector len {} != cols {}",
            v.len(),
            c
        )));
    }
    if o.len() != r {
        return Err(napi::Error::from_reason(format!(
            "forward_matvec_f32: output len {} != rows {}",
            o.len(),
            r
        )));
    }
    static FIRED: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
    if !FIRED.swap(true, std::sync::atomic::Ordering::Relaxed) {
        eprintln!(
            "[chaos:matvec] native forward_matvec_f32 engaged (rows={} cols={})",
            r, c
        );
    }
    // Rayon-parallel per-row dot product. All panic-prone checks already
    // returned above, so the inner loop is bounded by `c` and indexes only
    // validated slices -- rayon worker threads cannot panic here. The outer
    // `catch_unwind` in `forward_matvec_f32` still catches any stray unwind
    // as a backstop. Chunk size targets ~8 worker threads with amortized
    // task overhead; for 8192-row Q projections on an 8 vCPU Cloud Run
    // node this yields ~1024 rows per worker, keeping per-task cost in
    // the millisecond range rather than the per-row rayon overhead that
    // dominated par_chunks_mut(1).
    let chunk = ((r + 7) / 8).max(64);
    let cap = softcap.unwrap_or(0.0) as f32;
    let apply_softcap = cap > 0.0;

    o.par_chunks_mut(chunk)
        .enumerate()
        .for_each(|(chunk_idx, out_chunk)| {
            let row_start = chunk_idx * chunk;
            for (k, out_slot) in out_chunk.iter_mut().enumerate() {
                let i = row_start + k;
                let row = &m[i * c..(i + 1) * c];
                let mut acc: f32 = 0.0;
                for j in 0..c {
                    acc += row[j] * v[j];
                }
                if apply_softcap {
                    acc = (acc / cap).tanh() * cap;
                }
                *out_slot = acc;
            }
        });
    Ok(())
}

pub fn f16_to_f32(h: u16) -> f32 {
    let s = (h >> 15) & 0x0001;
    let e = (h >> 10) & 0x001f;
    let f = h & 0x03ff;

    if e == 0 {
        if f == 0 {
            return if s == 1 { -0.0 } else { 0.0 };
        }
        return (if s == 1 { -1.0 } else { 1.0 }) * (f as f32) * (2.0f32.powi(-24));
    } else if e == 31 {
        return 0.0;
    }
    let sign = if s == 1 { -1.0 } else { 1.0 };
    sign * (1.0 + f as f32 / 1024.0) * (2.0f32.powi(e as i32 - 15))
}

fn get_scale_min_k4(j: usize, scales: &[u8]) -> (f32, f32) {
    if j < 4 {
        ((scales[j] & 63) as f32, (scales[j + 4] & 63) as f32)
    } else {
        (
            ((scales[j + 4] & 0xf) | ((scales[j - 4] >> 6) << 4)) as f32,
            ((scales[j + 4] >> 4) | ((scales[j] >> 6) << 4)) as f32,
        )
    }
}

#[napi]
pub fn forward_matvec_q4k(
    matrix: Buffer,
    vector: Buffer,
    mut out: Buffer,
    rows: u32,
    cols: u32,
) -> napi::Result<()> {
    let w_slice = matrix.as_ref();
    let v_slice: &[f32] = bytemuck::try_cast_slice::<u8, f32>(vector.as_ref()).map_err(|e| {
        napi::Error::from_reason(format!("forward_matvec_q4k: vector cast failed: {}", e))
    })?;
    let out_slice: &mut [f32] =
        bytemuck::try_cast_slice_mut::<u8, f32>(out.as_mut()).map_err(|e| {
            napi::Error::from_reason(format!("forward_matvec_q4k: out cast failed: {}", e))
        })?;

    let r = rows as usize;
    let d = cols as usize;
    let blocks_per_row = d / 256;
    let expected_m = r * blocks_per_row * 144;

    if w_slice.len() != expected_m {
        return Err(napi::Error::from_reason(format!(
            "matrix len {} != {}",
            w_slice.len(),
            expected_m
        )));
    }
    if v_slice.len() != d {
        return Err(napi::Error::from_reason("vector len mismatch".to_string()));
    }
    if out_slice.len() != r {
        return Err(napi::Error::from_reason("output len mismatch".to_string()));
    }

    let w_addr = w_slice.as_ptr() as usize;

    let chunk = ((r + 7) / 8).max(64);
    out_slice
        .par_chunks_mut(chunk)
        .enumerate()
        .for_each(|(chunk_idx, out_chunk)| {
            let row_start = chunk_idx * chunk;
            for (k, out_slot) in out_chunk.iter_mut().enumerate() {
                let i = row_start + k;
                let mut row_sum = 0.0;
                let row_ptr = unsafe { (w_addr as *const u8).add(i * blocks_per_row * 144) };
                for b in 0..blocks_per_row {
                    let block_ptr = unsafe { row_ptr.add(b * 144) };
                    let x_offset = b * 256;
                    let d_val =
                        unsafe { f16_to_f32(u16::from_le_bytes([*block_ptr, *block_ptr.add(1)])) };
                    let dmin_val = unsafe {
                        f16_to_f32(u16::from_le_bytes([*block_ptr.add(2), *block_ptr.add(3)]))
                    };
                    let scales = unsafe { std::slice::from_raw_parts(block_ptr.add(4), 12) };
                    let qs = unsafe { std::slice::from_raw_parts(block_ptr.add(16), 128) };

                    for j in (0..256).step_by(64) {
                        let (sc1, m1) = get_scale_min_k4(j / 32, scales);
                        let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
                        let q_base = (j / 64) * 32;
                        for l in 0..32 {
                            row_sum += v_slice[x_offset + j + l]
                                * (d_val * sc1 * (qs[q_base + l] & 0xf) as f32 - dmin_val * m1);
                            row_sum += v_slice[x_offset + j + 32 + l]
                                * (d_val * sc2 * (qs[q_base + l] >> 4) as f32 - dmin_val * m2);
                        }
                    }
                }
                *out_slot = row_sum;
            }
        });

    Ok(())
}

#[napi]
pub fn forward_matvec_q6k(
    matrix: Buffer,
    vector: Buffer,
    mut out: Buffer,
    rows: u32,
    cols: u32,
) -> napi::Result<()> {
    let w_slice = matrix.as_ref();
    let v_slice: &[f32] = bytemuck::try_cast_slice::<u8, f32>(vector.as_ref()).map_err(|e| {
        napi::Error::from_reason(format!("forward_matvec_q6k: vector cast failed: {}", e))
    })?;
    let out_slice: &mut [f32] =
        bytemuck::try_cast_slice_mut::<u8, f32>(out.as_mut()).map_err(|e| {
            napi::Error::from_reason(format!("forward_matvec_q6k: out cast failed: {}", e))
        })?;

    let r = rows as usize;
    let d = cols as usize;
    let blocks_per_row = d / 256;
    let expected_m = r * blocks_per_row * 210;

    if w_slice.len() != expected_m {
        return Err(napi::Error::from_reason(format!(
            "matrix len {} != {}",
            w_slice.len(),
            expected_m
        )));
    }
    if v_slice.len() != d {
        return Err(napi::Error::from_reason("vector len mismatch".to_string()));
    }
    if out_slice.len() != r {
        return Err(napi::Error::from_reason("output len mismatch".to_string()));
    }

    let w_addr = w_slice.as_ptr() as usize;

    let chunk = ((r + 7) / 8).max(64);
    out_slice
        .par_chunks_mut(chunk)
        .enumerate()
        .for_each(|(chunk_idx, out_chunk)| {
            let row_start = chunk_idx * chunk;
            for (k, out_slot) in out_chunk.iter_mut().enumerate() {
                let i = row_start + k;
                let mut row_sum = 0.0;
                let row_ptr = unsafe { (w_addr as *const u8).add(i * blocks_per_row * 210) };
                for b in 0..blocks_per_row {
                    let block_ptr = unsafe { row_ptr.add(b * 210) };
                    let x_offset = b * 256;
                    let ql = unsafe { std::slice::from_raw_parts(block_ptr, 128) };
                    let qh = unsafe { std::slice::from_raw_parts(block_ptr.add(128), 64) };
                    let sc =
                        unsafe { std::slice::from_raw_parts(block_ptr.add(192) as *const i8, 16) };
                    let d_val = unsafe {
                        f16_to_f32(u16::from_le_bytes([
                            *block_ptr.add(208),
                            *block_ptr.add(209),
                        ]))
                    };

                    for group in 0..2 {
                        let n_sub = group * 128;
                        let ql_sub = &ql[group * 64..(group + 1) * 64];
                        let qh_sub = &qh[group * 32..(group + 1) * 32];
                        let sc_sub = &sc[group * 8..(group + 1) * 8];
                        for l in 0..32 {
                            let is = l / 16;
                            let q1 =
                                ((ql_sub[l] & 0xf) | (((qh_sub[l] >> 0) & 3) << 4)) as i32 - 32;
                            let q2 = ((ql_sub[l + 32] & 0xf) | (((qh_sub[l] >> 2) & 3) << 4))
                                as i32
                                - 32;
                            let q3 = ((ql_sub[l] >> 4) | (((qh_sub[l] >> 4) & 3) << 4)) as i32 - 32;
                            let q4 =
                                ((ql_sub[l + 32] >> 4) | (((qh_sub[l] >> 6) & 3) << 4)) as i32 - 32;

                            row_sum += v_slice[x_offset + n_sub + l]
                                * d_val
                                * (sc_sub[is + 0] as f32)
                                * (q1 as f32);
                            row_sum += v_slice[x_offset + n_sub + l + 32]
                                * d_val
                                * (sc_sub[is + 2] as f32)
                                * (q2 as f32);
                            row_sum += v_slice[x_offset + n_sub + l + 64]
                                * d_val
                                * (sc_sub[is + 4] as f32)
                                * (q3 as f32);
                            row_sum += v_slice[x_offset + n_sub + l + 96]
                                * d_val
                                * (sc_sub[is + 6] as f32)
                                * (q4 as f32);
                        }
                    }
                }
                *out_slot = row_sum;
            }
        });

    Ok(())
}

// ---------------------------------------------------------------------------
// Kernel 5: GPU-native TDA topology raymarcher
// ---------------------------------------------------------------------------

#[napi]
pub fn render_tda_frame(
    width: u32,
    height: u32,
    time: f64,
    betti_1: f64,
    active_nodes_low: u32,
    active_nodes_high: u32,
    adjacency_matrix: Buffer,
    profile_art: bool,
    lod: u32,
) -> napi::Result<String> {
    let adj_slice: &[u64] = match bytemuck::try_cast_slice::<u8, u64>(adjacency_matrix.as_ref()) {
        Ok(s) => s,
        Err(e) => {
            return Err(napi::Error::from_reason(format!(
                "render_tda_frame: matrix cast failed: {}",
                e
            )));
        }
    };

    if adj_slice.len() < 64 {
        return Err(napi::Error::from_reason(format!(
            "render_tda_frame: adjacency_matrix must be at least 64 u64s, got {}",
            adj_slice.len()
        )));
    }

    let mut matrix = [0u64; 64];
    matrix.copy_from_slice(&adj_slice[..64]);

    let active_mask_u64 = (active_nodes_high as u64) << 32 | (active_nodes_low as u64);

    let result_str = crate::tda_render::render_tda_frame(
        width,
        height,
        time as f32,
        betti_1 as f32,
        active_mask_u64,
        &matrix,
        profile_art,
        lod,
    );

    Ok(result_str)
}

#[cfg(test)]
mod bowl_filter_tests {
    //! Tests for the gated bowl Q-filter alternative inside
    //! `forward_median_shift_attention_impl`. Verifies the load-bearing
    //! distinction: the bowl path leaves a non-zero residual contribution
    //! at every position even where the legacy median-shift path zeroes
    //! below-cutoff slots (binary mask).
    use super::*;
    use std::sync::atomic::Ordering;

    /// Acquire exclusive use of the bowl-filter override for the test.
    /// Returned guard restores the override on drop so other tests in the
    /// same process are not affected (cargo runs tests in parallel by
    /// default; the BOWL_FILTER_TEST_OVERRIDE is a single atomic shared
    /// across threads).
    struct BowlGuard;
    impl BowlGuard {
        fn force_off() -> Self {
            BOWL_FILTER_TEST_OVERRIDE.store(1, Ordering::SeqCst);
            BowlGuard
        }
        fn force_on() -> Self {
            BOWL_FILTER_TEST_OVERRIDE.store(2, Ordering::SeqCst);
            BowlGuard
        }
    }
    impl Drop for BowlGuard {
        fn drop(&mut self) {
            BOWL_FILTER_TEST_OVERRIDE.store(0, Ordering::SeqCst);
        }
    }

    // Crude serializer: the bowl override is process-global. Two tests
    // flipping it at the same time would race. Cargo runs tests in
    // parallel, so we serialize the bowl-touching tests via a mutex.
    fn bowl_test_lock() -> &'static std::sync::Mutex<()> {
        static LOCK: OnceLock<std::sync::Mutex<()>> = OnceLock::new();
        LOCK.get_or_init(|| std::sync::Mutex::new(()))
    }

    /// Constructs a small known input where the legacy median-shift
    /// path zeroes the below-cutoff half (binary mask) and the bowl
    /// path damps it instead. Asserts:
    ///
    /// 1. Both paths produce same-shape output.
    /// 2. The bowl path's output differs from the legacy output (the
    ///    load-bearing distinction — below-cutoff positions still
    ///    contribute through the residual).
    /// 3. Both outputs are finite.
    /// 4. The aggregate dropped-mass-fraction has different semantics
    ///    between paths (legacy: z_dropped/z_full; bowl: z_damped/z_total).
    #[test]
    fn bowl_filter_preserves_below_cutoff_signal() {
        let _serial = bowl_test_lock().lock().unwrap_or_else(|p| p.into_inner());

        // Single head, single KV head — exercise the bowl branch directly
        // without GQA fan-out adding noise to the comparison.
        let seq_len: usize = 8;
        let head_dim: usize = 4;
        let num_heads: usize = 1;
        let num_kv_heads: usize = 1;
        let scale = 1.0f32 / (head_dim as f32).sqrt();

        // Deterministic q, k, v with enough score spread that the
        // median splits the kept/dropped sets non-trivially.
        let q: Vec<f32> = (0..num_heads * head_dim)
            .map(|i| (i as f32 + 1.0) * 0.25)
            .collect();
        let k: Vec<f32> = (0..num_kv_heads * seq_len * head_dim)
            .map(|i| ((i as f32) * 0.1).sin())
            .collect();
        // Use distinctive value vectors per position so the legacy
        // zero-out of below-cutoff positions is visibly different from
        // the bowl's damped contribution.
        let v: Vec<f32> = (0..num_kv_heads * seq_len * head_dim)
            .map(|i| (i as f32 + 1.0) * 1.5)
            .collect();

        // Legacy path — flag forced OFF.
        let mut out_legacy = vec![0.0f32; num_heads * head_dim];
        let tel_legacy = {
            let _guard = BowlGuard::force_off();
            forward_median_shift_attention_impl(
                &q,
                &k,
                &v,
                &mut out_legacy,
                seq_len,
                head_dim,
                num_heads,
                num_kv_heads,
                scale,
                // High ceiling: never trip the fallback so the median
                // prune actually runs.
                1.0,
            )
            .expect("legacy median-shift path must succeed")
        };

        // Bowl path — flag forced ON. Same inputs, same shapes.
        let mut out_bowl = vec![0.0f32; num_heads * head_dim];
        let tel_bowl = {
            let _guard = BowlGuard::force_on();
            forward_median_shift_attention_impl(
                &q,
                &k,
                &v,
                &mut out_bowl,
                seq_len,
                head_dim,
                num_heads,
                num_kv_heads,
                scale,
                1.0,
            )
            .expect("bowl-filter path must succeed")
        };

        // Same-shape outputs.
        assert_eq!(
            out_legacy.len(),
            out_bowl.len(),
            "both paths must produce same-shape outputs"
        );
        assert_eq!(out_legacy.len(), num_heads * head_dim);

        // Both outputs finite.
        for (i, &x) in out_legacy.iter().enumerate() {
            assert!(x.is_finite(), "legacy out[{}] not finite: {}", i, x);
        }
        for (i, &x) in out_bowl.iter().enumerate() {
            assert!(x.is_finite(), "bowl out[{}] not finite: {}", i, x);
        }

        // The bowl path must NOT be bitwise identical to the legacy
        // path — that is the load-bearing distinction. With damping=1
        // (default), below-cutoff positions contribute exps/2 to the
        // partition and the renormalized residual; the legacy path
        // zeroes them entirely.
        let max_diff = out_legacy
            .iter()
            .zip(out_bowl.iter())
            .map(|(a, b)| (a - b).abs())
            .fold(0.0f32, f32::max);
        assert!(
            max_diff > 1e-6,
            "bowl path must differ from legacy (max diff = {})",
            max_diff
        );

        // Sanity: the bowl path's per-head accounting reports BOTH
        // kept and "dropped" (= damped) positions for this input, and
        // their sum equals seq_len. Legacy path also satisfies the
        // same sum invariant.
        assert_eq!(
            (tel_legacy.kept_count + tel_legacy.dropped_count) as usize,
            num_heads * seq_len,
            "legacy telemetry must partition seq_len"
        );
        assert_eq!(
            (tel_bowl.kept_count + tel_bowl.dropped_count) as usize,
            num_heads * seq_len,
            "bowl telemetry must partition seq_len"
        );
        // The bowl path must have actually run (i.e. some positions
        // were damped, not all kept) for the distinction above to be
        // meaningful.
        assert!(
            tel_bowl.dropped_count > 0,
            "bowl test setup must produce a non-trivial damped set; got 0"
        );
    }
}
